#include<bits/stdc++.h>
using namespace std;
const long long mod=1e9+7;
long long fastpow(long long x,long long y)
{
    long long sum=1;
    while(y)
    {
        if(y%2==1)
        {
            sum=sum*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return sum;
}
int main()
{
    long long k,n;
    cin>>k>>n;
    printf("%lld",fastpow(2,k*n));
    return 0;
}
